import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerReturns = () => {
  const [returns, setReturns] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchReturns();
  }, []);

  const fetchReturns = async () => {
    try {
      const response = await axios.get(`${API_URL}/returns`);
      setReturns(response.data.data || response.data);
    } catch (error) {
      console.error('Error fetching returns:', error);
    } finally {
      setLoading(false);
    }
  };

  const getStatusStyle = (status) => {
    switch(status) {
      case 'PENDING':
        return { background: '#f8f9fa', color: '#495057' };
      case 'APPROVED':
        return { background: '#e9ecef', color: '#212529' };
      case 'REJECTED':
        return { background: '#dee2e6', color: '#212529' };
      default:
        return { background: '#f8f9fa', color: '#6c757d' };
    }
  };

  if (loading) {
    return (
      <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
        <div className="loading">Loading...</div>
      </div>
    );
  }

  return (
    <div className="main-content" style={{ marginLeft: 0, padding: '2rem' }}>
      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
          <h1 style={{ fontSize: '1.75rem', fontWeight: 600, color: '#212529' }}>My Returns</h1>
          <Link 
            to="/customer/returns/create" 
            style={{
              padding: '0.75rem 1.5rem',
              background: '#212529',
              color: 'white',
              textDecoration: 'none',
              borderRadius: '4px',
              fontSize: '0.95rem'
            }}
          >
            Request Return
          </Link>
        </div>

        {returns.length === 0 ? (
          <div style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', padding: '3rem', textAlign: 'center', color: '#6c757d' }}>
            No return requests found.
          </div>
        ) : (
          <div style={{ background: 'white', border: '1px solid #dee2e6', borderRadius: '8px', overflow: 'hidden' }}>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', minWidth: '800px' }}>
                <thead>
                  <tr style={{ background: '#f8f9fa', borderBottom: '1px solid #dee2e6' }}>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Return ID</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Date</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Rice Type</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Quantity</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Amount</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Status</th>
                    <th style={{ padding: '1rem', textAlign: 'left', fontSize: '0.85rem', fontWeight: 600, color: '#495057' }}>Reason</th>
                  </tr>
                </thead>
                <tbody>
                  {returns.map((returnReq) => (
                    <tr key={returnReq._id} style={{ borderBottom: '1px solid #dee2e6' }}>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>{returnReq.returnId}</td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>
                        {new Date(returnReq.createdAt).toLocaleDateString()}
                      </td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>{returnReq.riceType}</td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>{returnReq.quantityKg} kg</td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem' }}>₱{returnReq.amountPaid}</td>
                      <td style={{ padding: '1rem' }}>
                        <span style={{
                          padding: '0.25rem 0.5rem',
                          borderRadius: '4px',
                          fontSize: '0.85rem',
                          ...getStatusStyle(returnReq.status)
                        }}>
                          {returnReq.status}
                        </span>
                      </td>
                      <td style={{ padding: '1rem', fontSize: '0.95rem', color: '#6c757d' }}>
                        {returnReq.returnReason}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CustomerReturns;
